async function fixAxes() {
  let ok = 0, err = 0, skip = 0;

  for (const [idStr, axeFixes] of Object.entries(fixes)) {
    const id = parseInt(idStr);
    const { data: vwa, error: fetchErr } = await db.from('verse_word_analyses').select('id, word_key, analysis_axes').eq('id', id).single();
    if (fetchErr || !vwa) { console.log('SKIP VWA', id, '- not found', fetchErr?.message); skip++; continue; }

    const ax = vwa.analysis_axes;
    if (!ax || !ax.concepts) { console.log('SKIP VWA', id, '- no concepts'); skip++; continue; }
    const entries = Object.entries(ax.concepts);
    const retenu = entries.find(([_, c]) => c.status === 'retenu');
    if (!retenu) { console.log('SKIP VWA', id, '- no retenu'); skip++; continue; }

    const [conceptName, conceptData] = retenu;
    let changed = false;

    for (const [axeName, newText] of Object.entries(axeFixes)) {
      conceptData[axeName] = newText;
      changed = true;
    }

    if (changed) {
      ax.concepts[conceptName] = conceptData;
      const { error } = await db.from('verse_word_analyses').update({ analysis_axes: ax }).eq('id', id);
      if (error) { console.log('ERR VWA', id, vwa.word_key, error.message); err++; }
      else { console.log('OK VWA', id, vwa.word_key, '— axes enrichis:', Object.keys(axeFixes).join(', ')); ok++; }
    }
  }

  console.log(`\nDone: ${ok} OK, ${err} errors, ${skip} skipped`);
  console.log(`Total axes enrichis: ${Object.values(fixes).reduce((sum, f) => sum + Object.keys(f).length, 0)}`);
}

fixAxes().catch(console.error);
